/*!
 * Leaflet.Motion v1.0.5
 * https://github.com/Igor-Vladykin/Leaflet.Motion
 */
L.Motion = {};

L.Motion.Ease = {
    linear: t => t,
    inQuad: t => t * t,
    outQuad: t => t * (2 - t),
    inOutQuad: t => t < .5 ? 2 * t * t : (4 - 2 * t) * t - 1,
    inCubic: t => t * t * t,
    outCubic: t => (--t) * t * t + 1,
    inOutCubic: t => t < .5 ? 4 * t * t * t : (t - 1) * (2 * t - 2) * (2 * t - 2) + 1,
    inQuart: t => t * t * t * t,
    outQuart: t => 1 - (--t) * t * t * t,
    inOutQuart: t => t < .5 ? 8 * t * t * t * t : 1 - 8 * (--t) * t * t * t,
    inQuint: t => t * t * t * t * t,
    outQuint: t => (--t) * t * t * t * t + 1,
    inOutQuint: t => t < .5 ? 16 * t * t * t * t * t : 1 + 16 * (--t) * t * t * t * t,
    inExpo: t => 0 === t ? 0 : Math.pow(1024, t - 1),
    outExpo: t => 1 === t ? 1 : 1 - Math.pow(2, -10 * t),
    inOutExpo: t => 0 === t ? 0 : 1 === t ? 1 :
        t < .5 ? .5 * Math.pow(1024, 2 * t - 1) :
        .5 * (-Math.pow(2, -20 * t + 10) + 2),
    inBack: t => {
        let s = 1.70158;
        return t * t * ((s + 1) * t - s)
    },
    outBack: t => {
        let s = 1.70158;
        return 1 + (--t) * t * ((s + 1) * t + s)
    },
    inOutBack: t => {
        let s = 2.5949095;
        return t < .5 ?
            t * t * ((s + 1) * 2 * t - s) * 2 :
            ((t = 2 * t - 2) * t * ((s + 1) * t + s) + 2) / 2
    },
    inBounce: t => 1 - L.Motion.Ease.outBounce(1 - t),
    outBounce: t => t < 1 / 2.75 ?
        7.5625 * t * t :
        t < 2 / 2.75 ?
        7.5625 * (t -= 1.5 / 2.75) * t + .75 :
        t < 2.5 / 2.75 ?
        7.5625 * (t -= 2.25 / 2.75) * t + .9375 :
        7.5625 * (t -= 2.625 / 2.75) * t + .984375,
    inOutBounce: t =>
        t < .5 ?
        .5 * L.Motion.Ease.inBounce(2 * t) :
        .5 * L.Motion.Ease.outBounce(2 * t - 1) + .5
};

L.Motion.Tween = L.Class.extend({
    initialize: function(from, to, duration, easing, callback, done) {
        this._from = from;
        this._to = to;
        this._duration = duration;
        this._easing = easing || L.Motion.Ease.linear;
        this._callback = callback;
        this._done = done;

        this._start = null;
        this._anim = L.Util.bind(this._step, this);

        this._running = false;
    },

    run: function() {
        this._running = true;
        requestAnimationFrame(this._anim);
    },

    _step: function(timestamp) {
        if (!this._start) this._start = timestamp;
        const progress = Math.min((timestamp - this._start) / this._duration, 1);
        const value = this._from + (this._to - this._from) * this._easing(progress);

        this._callback(value);

        if (progress < 1 && this._running) {
            requestAnimationFrame(this._anim);
        } else {
            this._running = false;
            if (this._done) this._done();
        }
    },

    stop: function() {
        this._running = false;
    }
});

L.motion = function(layer, options, motionOptions, addOptions) {
    return new L.Motion.Layer(layer, options, motionOptions, addOptions);
};

L.Motion.Layer = L.Layer.extend({
    initialize: function(layer, options, motionOptions, addOptions) {
        this._layer = layer;
        this._motionOptions = motionOptions || {};
        this._addOptions = addOptions || {};

        this._duration = this._motionOptions.duration || 1000;
        this._easing = this._motionOptions.easing || L.Motion.Ease.linear;
    },

    onAdd: function(map) {
        this._map = map;
        map.addLayer(this._layer, this._addOptions);

        this._animate();
    },

    onRemove: function(map) {
        map.removeLayer(this._layer);
    },

    _animate: function() {
        const from = 0;
        const to = 1;

        this._tween = new L.Motion.Tween(
            from,
            to,
            this._duration,
            this._easing,
            progress => this._layer.setStyle ?
                this._layer.setStyle({
                    opacity: progress
                }) :
                null,
            () => {
                if (this._motionOptions.removeOnEnd) {
                    this._map.removeLayer(this._layer);
                }
            }
        );

        this._tween.run();
    }
});
